#include <iostream>
#include <vector>
#include <stack>
#include <tuple>
#include <climits>
using namespace std;

struct TreeNode {
    int value;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : value(x), left(NULL), right(NULL) {}
};

// Функция для добавления узла в дерево
TreeNode* insertNode(TreeNode*& current, char direction, int value) {
    if (direction == 'l') {
        current->left = new TreeNode(value);
        return current->left;
    } else { // direction == 'r'
        current->right = new TreeNode(value);
        return current->right;
    }
}

// Помощник функции для поиска максимальной суммы в допустимом BST поддереве
tuple<bool, int, int, int> findMaxBSTSum(TreeNode* node, int& max_sum) {
    if (!node) return make_tuple(true, 0, INT_MAX, INT_MIN);

    auto [is_bst_left, sum_left, min_left, max_left] = findMaxBSTSum(node->left, max_sum);
    auto [is_bst_right, sum_right, min_right, max_right] = findMaxBSTSum(node->right, max_sum);

    if (is_bst_left && is_bst_right &&
        node->value > max_left && node->value < min_right) {
        int sum = sum_left + sum_right + node->value;
        max_sum = max(max_sum, sum);
        return make_tuple(true, sum, min(min_left, node->value), max(max_right, node->value));
    }

    return make_tuple(false, 0, INT_MIN, INT_MAX);
}

