            TreeNode* node = insertNode(path.top(), direction, value);
            path.push(node);
        }
    }

    // Вычисление максимальной суммы в поддереве
    int max_sum = 0;
    findMaxBSTSum(root, max_sum);
    cout << max_sum << endl;

    // Cleanup code (optional)

    return 0;
}
