#include <iostream>
#include <vector>
#include <stack>
#include <climits>
using namespace std;

struct TreeNode {
    int value;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : value(x), left(NULL), right(NULL) {}
};

struct Info {
    bool isBST;
    int sum;
    int minValue;
    int maxValue;

    Info(bool isBST, int sum, int minValue, int maxValue)
        : isBST(isBST), sum(sum), minValue(minValue), maxValue(maxValue) {}
};

TreeNode* insert(TreeNode* node, char dir, int value) {
    TreeNode* newNode = new TreeNode(value);
    if (dir == 'l') {
        node->left = newNode;
    } else if (dir == 'r') {
        node->right = newNode;
    }
    return newNode;
}

Info findMaxBSTSubtree(TreeNode* node, int& maxSum) {
    if (!node) return {true, 0, INT_MAX, INT_MIN};

    Info left = findMaxBSTSubtree(node->left, maxSum);
    Info right = findMaxBSTSubtree(node->right, maxSum);

    if (left.isBST && right.isBST && node->value > left.maxValue && node->value < right.minValue) {
        int curSum = left.sum + right.sum + node->value;
        maxSum = max(maxSum, curSum);
        int minVal = min(node->value, left.minValue);
        int maxVal = max(node->value, right.maxValue);
        return {true, curSum, minVal, maxVal};
    }

    return {false, 0, INT_MIN, INT_MAX};
}

