Теперь программа будет ожидать ввода данных до тех пор, пока не будет достигнут конец файла (EOF), который может быть вызван ключевой комбинацией Ctrl+D (для Linux/Unix) или Ctrl+Z (для Windows) после ввода данных, или пока ввод не будет завершен каким-то другим способом.

Убедитесь, что при вводе данных каждому символу 'u' должен предшествовать соответствующий 'l' или 'r', чтобы гарантировать, что стек изменяется корректно.

#include <iostream>
#include <vector>

struct Node{
  int data;
  Node* parent = nullptr;
  Node* left = nullptr;
  Node* right = nullptr;
};

Node* Build(std::vector<char>& arr) {
  Node* root;
  for (int i = 0; i < arr.size(); ++i) {
    if (arr[i] == 'l') {
      Node* new_node = new Node;
      new_node->data = arr[i + 1];
      root->left = new_node;
      new_node->parent = root;
      root = root->left;
    } else if (arr[i] == 'r') {
      Node* new_node = new Node;
      new_node->data = arr[i + 1];
      root->right = new_node;
      new_node->parent = root;
      root = root->right;
    } else if (arr[i] == 'u') {
      if (root->parent != nullptr) {
        root = root->parent;
      } else {
        return root;
      }
    }
  }
  return root;
}

int MaxSumBST(Node* node, int& maxSum) {
    if (!node) return 0;

    int leftSum = MaxSumBST(node->left, maxSum);
    int rightSum = MaxSumBST(node->right, maxSum);
    int totalSum = node->data + leftSum + rightSum;

    // Проверяем, является ли текущее дерево BST
    if ((node->left == nullptr || (node->left->data < node->data && node->left == node->left->parent->left)) &&
        (node->right == nullptr || (node->right->data > node->data && node->right == node->right->parent->right))) {
        maxSum = std::max(maxSum, totalSum);
        return totalSum;
    }

    return 0; // Если не BST, не включаем этот узел в сумму
}

int main() {
  int c1 = 0;
  int c2 = 0;
  char cmd;
  std::vector<char> arr;
  while (std::cin >> cmd || c1 <= c2) {
    if (cmd == 'u') ++c1;
    if (cmd == 'l' || cmd == 'r') ++c2;
    arr.push_back(cmd);
